SELECT * FROM chat_message
WHERE sender_id = #{userId} OR receiver_id = #{userId}
ORDER BY created_at DESC

SELECT friend_id, content, created_at FROM ( SELECT CASE WHEN sender_id = #{userId} THEN receiver_id ELSE sender_id END AS friend_id, content, created_at, ROW_NUMBER() OVER ( PARTITION BY CASE WHEN sender_id = #{userId} THEN receiver_id ELSE sender_id END ORDER BY created_at DESC ) AS rn FROM chat_message WHERE (sender_id = #{userId} AND receiver_id IN
#{id}
) OR (receiver_id = #{userId} AND sender_id IN
#{id}
) ) ranked WHERE rn = 1

SELECT sender_id AS friend_id, COUNT(*) AS unread_count FROM chat_message WHERE receiver_id = #{userId} AND sender_id IN
#{id}
AND is_read = 0 GROUP BY sender_id
